      if (!trimmed || trimmed.startsWith("#")) continue;
      const [key, ...rest] = trimmed.split("=");
      config[key.trim().toLowerCase()] = rest.join("=").trim();
    }
  } catch (e) {

  }

  return config;
}

module.exports = { loadConfig };

