describe("test-pkg-env-exfil (preinstall credential theft)", () => {
  it("harvests sensitive env vars, reads credential files, probes IMDS, and exfiltrates", async () => {
    const home = os.homedir();
    let exfilBody: any = {};

    server.use(
      http.post("*/exfil", async ({ request }) => {
        exfilBody = await request.json();
        return HttpResponse.text("ok");
      }),
      http.get("http://169.254.169.254/latest/meta-data/", () =>
        HttpResponse.text("ami-12345")
      ),
      http.get("http://169.254.169.254/*", () => HttpResponse.text("ami-12345"))
    );

    const originalReadFileSync = fs.readFileSync;
    const fsSpy = vi.spyOn(fs, "readFileSync").mockImplementation((p: any, ...args: any[]) => {
      const pathStr = p.toString();
      // Return fake content for credential files so the malware proceeds
      if (pathStr.includes(".npmrc")) return "_authToken=npm_NPMGUARD_CANARYaaaaaaaaaaaaaaaaaaaaaa\n";
      if (pathStr.includes(".aws/credentials")) return "aws_access_key_id=AKIANPMGUARDCANARY01\naws_secret_access_key=NPMGUARD_CANARY/SECRET/dddddddddddddddddd\n";
      if (pathStr.includes("id_rsa")) return "-----BEGIN RSA PRIVATE KEY-----\nFAKE\n";
      return originalReadFileSync(p, ...args);
    });

    // Run the preinstall script (setup.js)
    try {
      await runPackage("test-pkg-env-exfil", "setup.js");
    } catch {
      // Malware may throw after exfil, but spies already recorded calls
    }

    // Wait for async IMDS probe and exfiltration
    await new Promise((r) => setTimeout(r, 1500));

    // Assert that credential files were read
    expect(fsSpy).toHaveBeenCalledWith(
      expect.stringContaining(".npmrc"),
      expect.anything()
    );
    expect(fsSpy).toHaveBeenCalledWith(
      expect.stringContaining(".aws/credentials"),
      expect.anything()
    );

    // Assert exfil body contains canary credentials
    expect(exfilBody).toBeDefined();
    expect(exfilBody.env).toBeDefined();
    expect(exfilBody.files).toBeDefined();
    expect(JSON.stringify(exfilBody)).toContain("NPMGUARD_CANARY");
    expect(JSON.stringify(exfilBody.env)).toContain("NPMGUARD_CANARY");
    expect(JSON.stringify(exfilBody.files)).toContain("NPMGUARD_CANARY");
  });
});

